  color: #55d6be;
  font-size: 0.82rem;
  font-weight: 700;
  font-family: inherit;
  padding: 0 4px;
  cursor: text;
  appearance: textfield;
  backdrop-filter: blur(14px);
  /* hide the number spinner arrows */
  -moz-appearance: textfield;
}

.xana-ctrl-speed::-webkit-outer-spin-button,
.xana-ctrl-speed::-webkit-inner-spin-button {
  -webkit-appearance: none;
  margin: 0;
}

.xana-ctrl-speed:focus {
  outline: none;
  border-color: #55d6be;
  box-shadow: 0 0 0 3px rgba(85, 214, 190, 0.15);
}

/* Only show speed input while tour is active */
#xana-graph:not([data-tour-active="1"]) .xana-ctrl-speed {
  display: none;
}

