html[data-xana-theme="classic"] .xana-search-results button {
  color: var(--xana-text);
}

html[data-xana-theme="light"] .xana-search-wrap,
html[data-xana-theme="classic"] .xana-search-wrap,
html[data-xana-theme="light"] .xana-ctrl-btn,
html[data-xana-theme="classic"] .xana-ctrl-btn,
html[data-xana-theme="light"] .xana-ctrl-speed,
html[data-xana-theme="classic"] .xana-ctrl-speed,
html[data-xana-theme="light"] .xana-filter-popover,
html[data-xana-theme="classic"] .xana-filter-popover,
html[data-xana-theme="light"] .xana-tools-popover,
html[data-xana-theme="classic"] .xana-tools-popover {
  background: var(--xana-panel-bg);
  border-color: var(--xana-panel-border);
  color: var(--xana-text);
  box-shadow: 0 12px 30px rgba(15, 23, 42, 0.14);
}

html[data-xana-theme="light"] .xana-search-prompt {
  color: rgba(15, 118, 110, 0.74);
}

html[data-xana-theme="classic"] .xana-search-prompt {
  color: #3366cc;
}

html[data-xana-theme="light"] .xana-panel,
html[data-xana-theme="classic"] .xana-panel {
  color: var(--xana-text);
}

html[data-xana-theme="light"] .xana-node-content,
html[data-xana-theme="classic"] .xana-node-content {
  color: var(--xana-text);
}

html[data-xana-theme="light"] .xana-inline-node,
html[data-xana-theme="light"] .xana-list-card {
  background: #ffffff;
  border-color: rgba(30, 41, 59, 0.16);
  box-shadow: 0 12px 28px rgba(15, 23, 42, 0.1);
}

html[data-xana-theme="classic"] .xana-inline-node,
html[data-xana-theme="classic"] .xana-list-card {
  background: #ffffff;
  border-color: #a2a9b1;
  border-radius: 2px;
  box-shadow: none;
}

html[data-xana-theme="light"] .xana-transclusion {
  background: #ffffff;
  border-color: rgba(15, 118, 110, 0.22);
}

html[data-xana-theme="classic"] .xana-transclusion {
  background: #ffffff;
  border-color: #a2a9b1;
  border-left-color: #3366cc;
  border-radius: 2px;
}

html[data-xana-theme="light"] .xana-transclusion-meta div,
html[data-xana-theme="classic"] .xana-transclusion-meta div {
  background: #ffffff;
  border-color: rgba(71, 85, 105, 0.22);
  color: var(--xana-text);
}

html[data-xana-theme="classic"] .xana-transclusion-meta div {
  border-color: #a2a9b1;
  border-radius: 2px;
}

html[data-xana-theme="light"] .xana-transclusion blockquote,
html[data-xana-theme="classic"] .xana-transclusion blockquote {
  background: transparent;
  color: var(--xana-text);
}

html[data-xana-theme="light"] .xana-source-info,
html[data-xana-theme="classic"] .xana-source-info {
  background: #ffffff;
  color: var(--xana-text);
}

html[data-xana-theme="light"] .xana-media-credit,
html[data-xana-theme="classic"] .xana-media-credit,
html[data-xana-theme="light"] .xana-node-image,
html[data-xana-theme="classic"] .xana-node-image,
html[data-xana-theme="light"] .xana-node-image--doc-placeholder,
html[data-xana-theme="classic"] .xana-node-image--doc-placeholder {
  background: #ffffff;
  border-color: rgba(71, 85, 105, 0.22);
  color: var(--xana-text-muted);
}

html[data-xana-theme="classic"] .xana-media-credit,
html[data-xana-theme="classic"] .xana-node-image,
html[data-xana-theme="classic"] .xana-node-image--doc-placeholder {
  border-color: #a2a9b1;
  border-radius: 2px;
}

html[data-xana-theme="light"] .xana-search-results button,
html[data-xana-theme="classic"] .xana-search-results button {
  background: var(--xana-surface);
  border-color: var(--xana-panel-border);
}

html[data-xana-theme="light"] .xana-search-result-snippet,
html[data-xana-theme="classic"] .xana-search-result-snippet,
html[data-xana-theme="light"] .xana-summary,
html[data-xana-theme="classic"] .xana-summary {
  color: var(--xana-text-muted);
}

html[data-xana-theme="classic"] .xana-navbar,
html[data-xana-theme="classic"] .xana-search-wrap,
html[data-xana-theme="classic"] .xana-filter-popover,
html[data-xana-theme="classic"] .xana-settings-panel,
html[data-xana-theme="classic"] .xana-tools-popover,
html[data-xana-theme="classic"] .xana-list-hero,
html[data-xana-theme="classic"] .xana-list-card,
html[data-xana-theme="classic"] .xana-ctrl-btn,
html[data-xana-theme="classic"] .xana-ctrl-speed {
  border-radius: 2px;
  backdrop-filter: none;
  -webkit-backdrop-filter: none;
}

html[data-xana-theme="classic"] .xana-panel {
  border-left: 1px solid var(--xana-panel-border);
}

html[data-xana-theme="classic"] a {
  color: #3366cc;
}

html[data-xana-theme="classic"] a:visited {
  color: #6b4ba1;
}

/* Audit meta badge — floats near controls strip when audit is active */

.xana-audit-meta {
  position: absolute;
  bottom: 4.5rem;
  left: 1.5rem;
  z-index: 30;
  background: rgba(255, 107, 107, 0.14);
  border: 1px solid rgba(255, 107, 107, 0.4);
  border-radius: 999px;
  color: #ff9a9a;
  font-size: 0.72rem;
  font-weight: 850;
  padding: 0.28rem 0.7rem;
  pointer-events: none;
  letter-spacing: 0.03em;
}

.xana-audit-meta[hidden] {
  display: none;
}

.xana-panel {
  min-width: 0;
  min-height: 0;
  height: 100%;
  overflow-y: auto;
  padding: 28px;
  background: var(--xana-panel-bg);
  font-size: calc(1rem * var(--xana-reader-scale));
  transition: opacity 180ms ease, filter 180ms ease;
}

.xana-panel.panel-transitioning {
  opacity: 0.45;
  filter: blur(1px);
}

.xana-panel h1 {
  font-size: calc(2.15rem * var(--xana-reader-scale));
  line-height: 1.05;
  margin: 0 0 16px;
}

.xana-panel h2 {
  font-size: 0.92em;
  color: var(--xana-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-top: 2rem;
}

.xana-type-badge {
  display: inline-flex;
  align-items: center;
  padding: 0.18rem 0.6rem;
  border-radius: 999px;
  font-size: 0.68em;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 0.65rem;
  background: var(--xana-badge-bg, rgba(255, 255, 255, 0.07));
  color: var(--xana-badge-fg, #94a3b8);
  border: 1px solid var(--xana-badge-border, rgba(255, 255, 255, 0.1));
}

.xana-node-badges {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 0.4rem;
  margin-bottom: 0.65rem;
}

.xana-node-badges .xana-type-badge {
  margin-bottom: 0;
}

.xana-subtype-badges {
  display: inline-flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.xana-subtype-badge {
  display: inline-flex;
  align-items: center;
  min-height: 1.35rem;
  padding: 0.14rem 0.5rem;
  border: 1px solid rgba(148, 163, 184, 0.28);
  border-radius: 999px;
  background: rgba(148, 163, 184, 0.1);
  color: var(--xana-text-muted);
  font-size: 0.66em;
  font-weight: 850;
  line-height: 1;
  text-transform: capitalize;
}

.xana-type-badge--sm {
  font-size: 0.6rem;
  padding: 0.1rem 0.42rem;
  margin-bottom: 0;
}

a.xana-type-badge-link {
  text-decoration: none;
  color: inherit;
  transition: transform 120ms ease, filter 120ms ease, border-color 120ms ease;
}

a.xana-type-badge-link:hover {
  transform: translateY(-1px);
  filter: brightness(1.08);
}

a.xana-type-badge-link:focus-visible {
  outline: 2px solid var(--xana-accent);
  outline-offset: 2px;
}

.xana-type-badge[data-type="concept"]      { --xana-badge-bg: var(--xana-section-concepts-soft); --xana-badge-fg: var(--xana-section-concepts); --xana-badge-border: var(--xana-section-concepts-border); }
.xana-type-badge[data-type="essay"]        { --xana-badge-bg: var(--xana-section-essays-soft); --xana-badge-fg: var(--xana-section-essays); --xana-badge-border: var(--xana-section-essays-border); }
.xana-type-badge[data-type="source"]       { --xana-badge-bg: var(--xana-section-sources-soft); --xana-badge-fg: var(--xana-section-sources); --xana-badge-border: var(--xana-section-sources-border); }
.xana-type-badge[data-type="person"]       { --xana-badge-bg: var(--xana-section-people-soft); --xana-badge-fg: var(--xana-section-people); --xana-badge-border: var(--xana-section-people-border); }
.xana-type-badge[data-type="observation"]  { --xana-badge-bg: var(--xana-section-observations-soft); --xana-badge-fg: var(--xana-section-observations); --xana-badge-border: var(--xana-section-observations-border); }
.xana-type-badge[data-type="trail"]        { --xana-badge-bg: var(--xana-section-trails-soft); --xana-badge-fg: var(--xana-section-trails); --xana-badge-border: var(--xana-section-trails-border); }
.xana-type-badge[data-type="project"]      { --xana-badge-bg: var(--xana-section-projects-soft); --xana-badge-fg: var(--xana-section-projects); --xana-badge-border: var(--xana-section-projects-border); }
.xana-type-badge[data-type="artifact"]     { background: rgba(167,243,208,0.12); color: #a7f3d0; border-color: rgba(167,243,208,0.3); }
.xana-type-badge[data-type="organization"] { --xana-badge-bg: var(--xana-section-organizations-soft); --xana-badge-fg: var(--xana-section-organizations); --xana-badge-border: var(--xana-section-organizations-border); }
.xana-type-badge[data-type="media"]        { --xana-badge-bg: var(--xana-section-media-soft); --xana-badge-fg: var(--xana-section-media); --xana-badge-border: var(--xana-section-media-border); }
.xana-type-badge[data-type="claim"]        { --xana-badge-bg: var(--xana-section-claims-soft); --xana-badge-fg: var(--xana-section-claims); --xana-badge-border: var(--xana-section-claims-border); }
.xana-type-badge[data-type="event"]        { --xana-badge-bg: var(--xana-section-events-soft); --xana-badge-fg: var(--xana-section-events); --xana-badge-border: var(--xana-section-events-border); }
.xana-type-badge[data-type="place"]        { --xana-badge-bg: var(--xana-section-place-soft); --xana-badge-fg: var(--xana-section-place); --xana-badge-border: var(--xana-section-place-border); }
.xana-type-badge[data-type="technology"]   { --xana-badge-bg: var(--xana-section-technologies-soft); --xana-badge-fg: var(--xana-section-technologies); --xana-badge-border: var(--xana-section-technologies-border); }
.xana-type-badge[data-type="publication"]  { background: rgba(167,139,250,0.12); color: #a78bfa; border-color: rgba(167,139,250,0.3); }
.xana-type-badge[data-type="community"]    { background: rgba(251,146,60,0.12); color: #fb923c; border-color: rgba(251,146,60,0.3); }
.xana-type-badge[data-type="relationship"] { background: rgba(236,72,153,0.12); color: #ec4899; border-color: rgba(236,72,153,0.3); }
.xana-type-badge[data-type="revision"]     { background: rgba(100,116,139,0.12); color: #94a3b8; border-color: rgba(100,116,139,0.3); }
.xana-type-badge[data-type="schema"]       { background: rgba(226,232,240,0.08); color: #e2e8f0; border-color: rgba(226,232,240,0.2); }

.xana-summary {
  color: #cbd5e1;
}

.xana-node-header {
  display: grid;
  gap: 22px;
  align-items: start;
  margin-bottom: 26px;
}

.xana-node-header.has-media {
  grid-template-columns: 112px minmax(0, 1fr);
}

.xana-node-header.no-media {
  grid-template-columns: minmax(0, 1fr);
}

.xana-node-heading-text {
  min-width: 0;
}

.xana-node-header h1 {
  margin-top: 0;
}

.xana-node-image,
.xana-node-image-link {
  width: 112px;
  height: 112px;
  border-radius: 22px;
}

.xana-node-image {
  object-fit: cover;
  object-position: center;
  border: 2px solid #55d6be;
  background: var(--xana-surface-elevated);
  box-shadow: 0 0 28px rgba(85, 214, 190, 0.18);
}

.xana-node-image--panel {
  object-fit: contain;
  background: var(--xana-surface-elevated);
}

.xana-node-image--contain {
  object-fit: contain;
  object-position: center;
  background: var(--xana-surface-elevated);
}

.xana-node-image-link {
  display: block;
}

.xana-node-image-link:hover .xana-node-image {
  border-color: #ffd166;
  box-shadow: 0 0 34px rgba(255, 209, 102, 0.25);
}

.xana-node-image-link.unresolved-media {
  cursor: not-allowed;
  position: relative;
}

.xana-node-image-link.unresolved-media::after {
  content: "unresolved";
  position: absolute;
  left: 8px;
  bottom: 8px;
  padding: 2px 6px;
  border-radius: 999px;
  background: #ff6b6b;
  color: #05070a;
  font-size: 0.65rem;
  font-weight: 900;
}

/* ── Document / audio / video media card ───────────────────────────────── */

.xana-node-image--doc-placeholder {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.35rem;
  background: var(--xana-surface-elevated);
  border: 1px solid var(--xana-panel-border);
  border-radius: 8px;
  color: var(--xana-text-muted);
  text-decoration: none;
  transition: background 0.15s, border-color 0.15s, color 0.15s;
}

.xana-node-image--doc-placeholder:hover {
  background: rgba(85, 214, 190, 0.08);
  border-color: rgba(85, 214, 190, 0.35);
  color: #55d6be;
}

.xana-node-image--doc-placeholder svg {
  width: 2rem;
  height: 2rem;
}

.xana-doc-placeholder-ext {
  font-size: 0.6rem;
  font-weight: 800;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.xana-node-content {
  line-height: 1.7;
  color: var(--xana-text);
  overflow-wrap: anywhere;
}

.xana-node-content p {
  margin-bottom: 1rem;
}

.xana-node-content a {
  color: var(--xana-accent);
}

.xana-node-content a[href^="http"]::after {
  content: " ↗";
  opacity: 0.7;
}

.xana-node-content img {
  max-width: 100%;
  height: auto;
  border-radius: 18px;
  border: 1px solid var(--xana-panel-border);
  margin: 1.5rem 0;
  display: block;
}

.xana-node-content figure {
  margin: 1.5rem 0;
}

.xana-node-content figcaption {
  color: var(--xana-text-muted);
  font-size: 0.9rem;
  margin-top: 0.5rem;
}

.xana-youtube-embed {
  margin: 1.5rem 0;
}

.xana-youtube-embed__frame {
  position: relative;
  aspect-ratio: 16 / 9;
  border-radius: 18px;
  overflow: hidden;
  border: 1px solid var(--xana-panel-border);
  background: var(--xana-surface-elevated);
}

.xana-youtube-embed__frame iframe {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  border: 0;
}

.xana-youtube-embed__link {
  display: inline-flex;
  margin-top: 0.7rem;
  color: var(--xana-accent);
  font-weight: 700;
}

.xana-pdf-embed {
  margin: 1.5rem 0;
}

.xana-pdf-embed__frame {
  position: relative;
  min-height: 720px;
  border-radius: 18px;
  overflow: hidden;
  border: 1px solid var(--xana-panel-border);
  background: var(--xana-surface-elevated);
}

.xana-pdf-embed__frame iframe {
  width: 100%;
  height: 100%;
  min-height: 720px;
  border: 0;
}

.xana-pdf-embed__link {
  display: inline-flex;
  margin-top: 0.7rem;
  color: var(--xana-accent);
  font-weight: 700;
}

/* Connections <details> section */
.xana-connections {
  margin-top: 1.75rem;
}

.xana-connections-summary {
  list-style: none;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  cursor: pointer;
  font-size: 0.75rem;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--xana-text-muted);
  padding: 0.6rem 0;
  border-top: 1px solid var(--xana-panel-border);
  user-select: none;
}

.xana-connections-summary::-webkit-details-marker { display: none; }
.xana-connections-summary::marker { display: none; }

.xana-connections-summary::before {
  content: "\25B6";
  font-size: 0.6rem;
  transition: transform 180ms;
  color: var(--xana-text-muted);
}

.xana-connections[open] .xana-connections-summary::before {
  transform: rotate(90deg);
}

.xana-conn-count {
  background: var(--xana-accent-soft);
  border-radius: 999px;
  padding: 0.1rem 0.48rem;
  font-size: 0.68rem;
  color: var(--xana-accent);
}

.xana-connections-group {
  margin: 0.6rem 0 1rem;
}

.xana-connections-dir-label {
  font-size: 0.65rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--xana-text-muted);
  font-weight: 850;
  margin-bottom: 0.4rem;
}

/* Relation list */
.xana-relations {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.3rem;
}

.xana-rel-link {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  padding: 0.55rem 0.7rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.8rem;
  text-decoration: none;
  background: var(--xana-surface-elevated);
  transition: border-color 120ms, background 120ms;
}

.xana-rel-link:hover {
  border-color: var(--xana-accent-border);
  background: var(--xana-accent-soft);
}

.xana-rel-title {
  color: var(--xana-text);
  font-weight: 850;
  font-size: 0.875rem;
  line-height: 1.25;
}

.xana-rel-meta {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  flex-wrap: wrap;
}

.xana-rel-edge-type {
  font-size: 0.65rem;
  color: var(--xana-text-muted);
  font-weight: 750;
}

.xana-rel-weight {
  font-size: 0.6rem;
  color: var(--xana-text-muted);
  letter-spacing: 0.05em;
}

.xana-media-credit {
  margin-top: 12px;
  padding: 10px 12px;
  border: 1px solid var(--xana-panel-border);
  border-radius: 12px;
  background: var(--xana-surface-elevated);
  color: var(--xana-text-muted);
  font-size: 0.78rem;
}

.xana-media-credit a {
  display: block;
  color: var(--xana-accent);
  font-weight: 850;
  margin-bottom: 4px;
}

.xana-media-credit span {
  display: block;
}

.xana-protocol-footer {
  display: grid;
  gap: 0.45rem;
  margin: 1.35rem 0 0;
  padding: 0.75rem 0;
  border-top: 1px solid var(--xana-panel-border);
  color: var(--xana-text-muted);
  font-size: 0.72rem;
}

.xana-protocol-footer div {
  min-width: 0;
}

.xana-protocol-footer span {
  display: block;
  margin-bottom: 0.16rem;
  font-weight: 900;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.xana-protocol-footer code {
  display: block;
  overflow-wrap: anywhere;
  color: var(--xana-accent);
  font-size: 0.74rem;
}

.xana-fragment-highlight {
  position: relative;
  border-radius: 0.55rem;
  outline: 3px solid rgba(255, 209, 102, 0.95);
  outline-offset: 4px;
  background: linear-gradient(90deg, rgba(255, 209, 102, 0.22), rgba(85, 214, 190, 0.1));
  box-shadow: 0 0 0 7px rgba(255, 209, 102, 0.1), 0 0 28px rgba(255, 209, 102, 0.22);
}

.xana-fragment-highlight::before {
  content: attr(data-fragment-label);
  display: inline-block;
  margin: 0 0 0.55rem;
  padding: 0.25rem 0.45rem;
  border: 1px solid rgba(255, 209, 102, 0.55);
  border-radius: 0.4rem;
  background: rgba(255, 209, 102, 0.16);
  color: #ffd166;
  font-size: 0.68rem;
  font-weight: 900;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.xana-fragment-note {
  margin: 0 0 1rem;
  padding: 0.75rem 0.85rem;
  border: 1px solid rgba(255, 209, 102, 0.45);
  border-radius: 0.7rem;
  background: rgba(255, 209, 102, 0.12);
  color: var(--xana-text);
}

.xana-fragment-note span {
  display: block;
  margin-bottom: 0.3rem;
  color: var(--xana-text-muted);
  font-size: 0.68rem;
  font-weight: 900;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.xana-fragment-note code {
  overflow-wrap: anywhere;
  color: #ffd166;
}

.xana-trail-playlist {
