.xana-review-status {
  flex: 0 0 auto;
  padding: 0.2rem 0.5rem;
  border: 1px solid rgba(148, 163, 184, 0.26);
  border-radius: 999px;
  color: #cbd5e1;
  font-size: 0.68rem;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.xana-review-card[data-review-status="implemented"] .xana-review-status {
  border-color: rgba(85, 214, 190, 0.42);
  background: rgba(85, 214, 190, 0.12);
  color: #55d6be;
}

.xana-list-card {
  padding: 18px 18px 16px;
  transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease, background 180ms ease;
}

.xana-list-card--source {
  border-color: rgba(85, 214, 190, 0.2);
}

.xana-list-card:hover {
  transform: translateY(-2px);
  border-color: var(--xana-accent-border);
  box-shadow: 0 16px 42px rgba(0, 0, 0, 0.28);
  background:
    linear-gradient(180deg, rgba(21, 26, 34, 0.98), rgba(11, 15, 20, 0.98));
}

.xana-list-card-main {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 1rem;
}

.xana-list-card-media {
  display: block;
  width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 6px;
  background: rgba(2, 6, 23, 0.38);
}

.xana-list-card-media img {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: contain;
}

.xana-list-card-body {
  min-width: 0;
}

.xana-list-card-topline {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 0.8rem;
}

.xana-list-badges {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 0.4rem;
  min-width: 0;
}

.xana-list-type {
  color: var(--xana-accent);
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 0.7rem;
  font-weight: 900;
}

.xana-list-subtype {
  color: #bfdbfe;
  border: 1px solid rgba(96, 165, 250, 0.26);
  border-radius: 999px;
  padding: 0.12rem 0.45rem;
  background: rgba(59, 130, 246, 0.08);
  text-transform: capitalize;
  font-size: 0.68rem;
  font-weight: 800;
  line-height: 1.2;
}

.xana-list-importance {
  color: #94a3b8;
  font-size: 0.72rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  white-space: nowrap;
}

.xana-list-card h2 {
  margin: 0 0 0.75rem;
  font-size: 1.25rem;
  line-height: 1.2;
}

.xana-list-card h2 a {
  color: #f8fafc;
}

.xana-list-card h2 a:hover {
  color: var(--xana-accent);
}

.xana-list-card p {
  margin: 0;
  color: #cbd5e1;
  line-height: 1.6;
}

.xana-list-empty {
  color: #94a3b8;
}

.xana-list-mini-meta {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 0.55rem;
  margin: 1rem 0 0;
  padding: 0.9rem 0 0;
  border-top: 1px solid rgba(148, 163, 184, 0.16);
}

.xana-list-mini-meta div {
  display: grid;
  grid-template-columns: 5.5rem minmax(0, 1fr);
  gap: 0.75rem;
  align-items: baseline;
}

.xana-list-mini-meta dt {
  color: #94a3b8;
  font-size: 0.68rem;
  font-weight: 900;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.xana-list-mini-meta dd {
  min-width: 0;
  margin: 0;
  color: #dbeafe;
  overflow-wrap: anywhere;
}

.xana-list-mini-meta a {
  color: var(--xana-accent);
  font-weight: 800;
}

.xana-list-mini-meta code {
  color: var(--xana-accent);
  font-size: 0.82em;
  white-space: normal;
}

.xana-list-card-footer {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-top: 1rem;
}

.xana-list-card-footer a {
  color: var(--xana-accent);
  font-size: 0.9rem;
  font-weight: 700;
}

.xana-list-card-footer a:hover {
  text-decoration: underline;
}

@media (min-width: 680px) {
  .xana-list-card:has(.xana-list-card-media) .xana-list-card-main {
    grid-template-columns: minmax(120px, 0.35fr) minmax(0, 1fr);
  }
}

@media (max-width: 520px) {
  .xana-list-card-topline {
    align-items: flex-start;
    flex-direction: column;
  }

  .xana-list-mini-meta div {
    grid-template-columns: minmax(0, 1fr);
    gap: 0.15rem;
  }
}

@media (max-width: 1100px) {
  .xana-searcher {
    width: clamp(280px, 62%, 500px);
  }
}

@media (max-width: 900px) {
  html,
  body {
    overflow: hidden;
  }

  .xana-app {
    width: 100%;
    min-height: 100svh;
    height: 100svh;
    display: grid;
    grid-template-columns: 1fr;
    grid-template-rows: 48px 1fr;
    overflow: hidden;
    --xana-mobile-panel-height: min(48svh, 440px);
    --xana-mobile-search-height: 112px;
    --xana-mobile-controls-height: 52px;
  }

  .xana-list-page {
    padding: 24px 16px 40px;
  }

  .xana-list-hero {
    padding: 22px 18px 18px;
    border-radius: 22px;
  }

  .xana-list-metrics {
    grid-template-columns: 1fr;
  }

  .xana-list-grid {
    grid-template-columns: 1fr;
  }

  .xana-navbar {
    grid-column: 1;
    grid-row: 1;
    padding: 0 0.75rem;
    min-width: 0;
  }

  .xana-brand-home {
    min-width: 0;
    max-width: 100%;
    gap: 0.45rem;
    padding: 0.25rem 0.45rem 0.25rem 0.2rem;
  }

  .xana-brand-icon {
    width: 24px;
    height: 24px;
    flex: 0 0 24px;
  }

  .xana-brand-text {
    min-width: 0;
  }

  .xana-brand-name {
    font-size: 0.78rem;
  }

  .xana-brand-tagline {
    display: block;
    max-width: calc(100vw - 6rem);
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    font-size: 0.52rem;
    letter-spacing: 0.02em;
  }

  .xana-resizer {
    display: none;
  }

  #xana-graph {
    grid-row: 2;
    align-self: start;
    height: calc(100svh - 48px - var(--xana-mobile-panel-height));
    min-height: 0;
  }

  #xana-stage {
    position: absolute;
    left: 0;
    right: 0;
    top: var(--xana-mobile-search-height);
    bottom: var(--xana-mobile-controls-height);
    height: auto;
  }

  .xana-panel {
    position: fixed;
    left: 0;
    right: 0;
    bottom: 0;
    z-index: 80;
    height: var(--xana-mobile-panel-height);
    min-height: 260px;
    max-height: 58svh;
    overflow-y: auto;
    padding: 22px;
    background: var(--xana-bg);
    border-top: 1px solid var(--xana-panel-border);
    box-shadow: 0 -22px 70px rgba(0, 0, 0, 0.56);
    border-radius: 16px 16px 0 0;
  }

  .xana-panel.panel-transitioning {
    opacity: 1;
    filter: none;
  }

  .xana-attribution {
    bottom: 0.75rem;
    right: 0.6rem;
    z-index: 31;
    max-width: calc(100vw - 1.2rem);
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }

  .xana-searcher {
    top: 0.7rem;
    left: 0.75rem;
    right: 0.75rem;
    transform: none;
    width: auto;
    max-width: none;
    box-sizing: border-box;
  }

  html[data-xana-density="compact"] .xana-searcher {
    width: auto;
    max-width: none;
  }

  .xana-search-wrap {
    width: 100%;
    box-sizing: border-box;
    border-radius: 1.25rem;
    padding: 0.5rem 0.55rem 0.5rem 0.9rem;
  }

  html[data-xana-density="compact"] .xana-search-wrap {
    padding: 0.46rem 0.55rem 0.46rem 0.9rem;
  }

  .xana-search-form textarea,
  .xana-search-prompt {
    font-size: 0.92rem;
  }

  .xana-depth-row {
    justify-content: center;
    gap: 0.35rem;
    padding: 0.35rem 0.15rem 0;
  }

  .xana-depth-row button {
    flex: 1 1 0;
    max-width: 5.5rem;
  }

  .xana-search-results {
    max-height: min(32svh, calc(100svh - var(--xana-mobile-panel-height) - var(--xana-mobile-search-height) - 96px));
  }

  .xana-controls-strip {
    left: 1rem;
    right: 1rem;
    bottom: 0.6rem;
    min-height: 38px;
    max-width: calc(100vw - 2rem);
    flex-wrap: wrap;
    justify-content: center;
  }

  .xana-settings,
  .xana-tools-popover {
    inset: 0;
    z-index: 140;
    padding: 4.5rem 1rem 2rem;
  }

  .xana-filter-popover {
    inset: 0;
    z-index: 140;
    width: auto;
    max-width: none;
    padding: 4.5rem 1rem 2rem;
  }

  .xana-audit-meta {
    left: 1rem;
    z-index: 95;
    bottom: 4rem;
  }
}

@media (max-width: 700px) {
  .xana-app {
    grid-template-rows: 48px 1fr;
    --xana-mobile-panel-height: min(50svh, 420px);
    --xana-mobile-search-height: 104px;
    --xana-mobile-controls-height: 48px;
  }

  #xana-graph {
    height: calc(100svh - 48px - var(--xana-mobile-panel-height));
    min-height: 0;
  }

  .xana-panel {
    padding: 18px;
  }

  .xana-settings,
  .xana-tools-popover {
    inset: 0;
    padding: 4.25rem 0.9rem 2rem;
  }

  .xana-settings-panel,
  .xana-tools-popover {
    width: 100%;
    max-height: none;
  }

  .xana-controls-strip {
    gap: 0.25rem;
  }

  .xana-ctrl-sep {
    display: none;
  }

  .xana-ctrl-btn {
    width: 30px;
    height: 30px;
  }

  .xana-interface-tour-card {
    right: 0.75rem;
    left: 0.75rem;
    top: calc(48px + 0.75rem);
    width: auto;
    max-height: min(36svh, 280px);
    background: var(--xana-bg);
  }

  .xana-trail-playlist-items button {
    grid-template-columns: 30px minmax(0, 1fr);
  }

  .xana-trail-playlist-items button em {
    grid-column: 2;
  }

  .xana-node-header,
  .xana-node-header.has-media,
  .xana-node-header.no-media {
    grid-template-columns: 1fr;
  }

  .xana-node-image,
  .xana-node-image-link {
    width: 96px;
    height: 96px;
  }
}

/* ── Schema audit stage ──────────────────────────────────────────────────── */

#xana-audit-stage,
#xana-path-stage {
  position: fixed;
  inset: 0;
  z-index: 130;
  overflow-y: auto;
  background: var(--xana-bg);
}

.xana-audit-page {
  padding: 6rem 2rem 3rem;
  max-width: 860px;
  margin: 0 auto;
}

.xana-audit-page-header {
  margin-bottom: 2rem;
  padding-bottom: 1.25rem;
  border-bottom: 1px solid var(--xana-panel-border);
}

.xana-audit-header-row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 1rem;
  flex-wrap: wrap;
}

.xana-audit-title {
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--xana-text);
  margin: 0 0 0.3rem;
}

.xana-audit-summary {
  color: var(--xana-text-muted);
  font-size: 0.9rem;
  margin: 0;
}

.xana-audit-dismiss {
  background: var(--xana-surface-elevated);
  border: 1px solid var(--xana-panel-border);
  color: var(--xana-text);
  border-radius: 0.65rem;
  padding: 0.45rem 0.85rem;
  font-size: 0.82rem;
  font-weight: 700;
  cursor: pointer;
  white-space: nowrap;
  flex-shrink: 0;
}

.xana-audit-dismiss:hover {
  background: var(--xana-accent-soft);
  border-color: var(--xana-accent);
  color: var(--xana-accent);
}

.xana-audit-page-body {
  display: grid;
  gap: 1.5rem;
}

.xana-audit-group {
  background: var(--xana-panel-bg);
  border: 1px solid var(--xana-panel-border);
  border-radius: 1rem;
  padding: 1rem 1.1rem;
}

.xana-audit-group-title {
  font-size: 0.82rem;
  font-weight: 850;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: #ff6b6b;
  margin: 0 0 0.75rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.xana-audit-count {
  background: rgba(255, 107, 107, 0.18);
  color: var(--xana-section-claims);
  border-radius: 999px;
  padding: 0.1rem 0.5rem;
  font-size: 0.78rem;
  font-weight: 900;
  letter-spacing: 0;
}

.xana-audit-node-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.35rem;
}

.xana-audit-node-btn {
  width: 100%;
  text-align: left;
  background: var(--xana-surface-elevated);
  border: 1px solid transparent;
  border-radius: 0.65rem;
  padding: 0.5rem 0.75rem;
  cursor: pointer;
  display: grid;
  grid-template-columns: 1fr auto;
  grid-template-rows: auto auto;
  gap: 0.1rem 0.5rem;
  align-items: start;
}

.xana-audit-node-btn:hover {
  background: var(--xana-accent-soft);
  border-color: var(--xana-accent);
}

.xana-audit-node-title {
  grid-column: 1;
  grid-row: 1;
  font-weight: 800;
  font-size: 0.88rem;
  color: var(--xana-text);
}

.xana-audit-node-type {
  grid-column: 2;
  grid-row: 1;
  font-size: 0.72rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--xana-accent);
  white-space: nowrap;
}

.xana-audit-node-msg {
  grid-column: 1 / -1;
  grid-row: 2;
  font-size: 0.78rem;
  color: var(--xana-text-muted);
}

/* ── Path explorer page ─────────────────────────────────────────────────── */

.xana-path-page {
  padding: 6rem 2rem 3rem;
  max-width: 980px;
  margin: 0 auto;
}

.xana-path-page-header {
  margin-bottom: 2rem;
  padding-bottom: 1.25rem;
  border-bottom: 1px solid var(--xana-panel-border);
}

.xana-path-header-row {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 1rem;
  flex-wrap: wrap;
}

.xana-path-title {
  font-size: 1.5rem;
  font-weight: 900;
  color: var(--xana-text);
  margin: 0 0 0.3rem;
}

.xana-path-summary {
  color: var(--xana-text-muted);
  font-size: 0.9rem;
  margin: 0;
}

.xana-path-dismiss {
  background: var(--xana-surface-elevated);
  border: 1px solid var(--xana-panel-border);
  color: var(--xana-text);
  border-radius: 0.65rem;
  padding: 0.45rem 0.85rem;
  font-size: 0.82rem;
  font-weight: 700;
  cursor: pointer;
  white-space: nowrap;
  flex-shrink: 0;
}

.xana-path-dismiss:hover {
  background: var(--xana-accent-soft);
  border-color: var(--xana-accent);
  color: var(--xana-accent);
}

.xana-path-page-body {
  display: grid;
  gap: 1rem;
}

.xana-path-form {
  display: grid;
  gap: 1rem;
  padding: 1rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 1rem;
  background: var(--xana-panel-bg);
}

.xana-path-grid {
  display: grid;
  gap: 0.85rem;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.xana-path-field {
  display: grid;
  gap: 0.4rem;
  color: var(--xana-text-muted);
  font-size: 0.82rem;
  font-weight: 700;
}

.xana-path-field input {
  width: 100%;
  padding: 0.6rem 0.75rem;
  background: var(--xana-surface-elevated);
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.75rem;
  color: var(--xana-text);
  font-size: 0.92rem;
}

.xana-path-field input:focus {
  outline: none;
  border-color: var(--xana-accent);
  box-shadow: 0 0 0 3px rgba(85, 214, 190, 0.12);
}

.xana-path-field-btn {
  justify-self: start;
  background: var(--xana-accent-soft);
  border: 1px solid var(--xana-accent-border);
  color: var(--xana-accent);
  border-radius: 999px;
  padding: 0.28rem 0.65rem;
  font-size: 0.74rem;
  font-weight: 800;
  cursor: pointer;
}

.xana-path-field-btn:hover {
  background: var(--xana-accent-soft);
  border-color: var(--xana-accent);
}

.xana-path-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem;
  align-items: center;
}

.xana-path-toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  color: var(--xana-text-muted);
  font-size: 0.82rem;
  font-weight: 700;
}

.xana-path-hop-limit {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  color: var(--xana-text-muted);
  font-size: 0.82rem;
  font-weight: 700;
}

.xana-path-hop-limit input {
  width: 4.2rem;
  min-height: 34px;
  padding: 0 0.55rem;
  border: 1px solid var(--xana-panel-border);
  border-radius: 0.65rem;
  background: var(--xana-surface-elevated);
  color: var(--xana-text);
  font: inherit;
}

.xana-path-swap,
.xana-path-trace {
  border-radius: 0.75rem;
  padding: 0.5rem 0.85rem;
  font-size: 0.82rem;
  font-weight: 800;
  cursor: pointer;
  border: 1px solid var(--xana-panel-border);
  background: var(--xana-surface-elevated);
  color: var(--xana-text);
}

.xana-path-swap:hover,
.xana-path-trace:hover:not(:disabled) {
  background: var(--xana-accent-soft);
  border-color: var(--xana-accent);
}

.xana-path-trace:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.xana-path-meta {
  color: var(--xana-text-muted);
  font-size: 0.88rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
}

.xana-path-empty {
  margin: 0;
  padding: 1rem 1.1rem;
  border: 1px dashed var(--xana-panel-border);
  border-radius: 0.9rem;
  color: var(--xana-text-muted);
  background: var(--xana-surface-elevated);
}

.xana-path-results {
  display: grid;
  gap: 0.85rem;
}

.xana-path-summary-line {
  margin: 0;
  color: var(--xana-text-muted);
  font-size: 0.88rem;
}

.xana-path-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.85rem;
}

.xana-path-card {
  border: 1px solid var(--xana-panel-border);
  border-radius: 1rem;
  background: var(--xana-panel-bg);
  padding: 1rem 1.05rem;
}

.xana-path-card-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 1rem;
  flex-wrap: wrap;
  margin-bottom: 0.85rem;
}

.xana-path-card-header h3 {
  margin: 0 0 0.2rem;
  font-size: 1rem;
  color: var(--xana-text);
}

.xana-path-card-header p {
  margin: 0;
  color: var(--xana-text-muted);
  font-size: 0.8rem;
}

.xana-path-story {
  margin: 0 0 0.85rem;
  color: var(--xana-text);
  font-size: calc(0.92rem * var(--xana-reader-scale, 1));
  line-height: 1.65;
}

.xana-path-card-endpoints {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  flex-wrap: wrap;
  justify-content: flex-end;
}

.xana-path-hop-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.45rem;
}

.xana-path-hop {
  display: grid;
  grid-template-columns: auto minmax(0, 1fr) auto auto auto minmax(0, 1fr);
  gap: 0.45rem;
  align-items: center;
  padding: 0.55rem 0.65rem;
  border-radius: 0.8rem;
  background: var(--xana-surface-elevated);
  border: 1px solid var(--xana-panel-border);
}

.xana-path-hop-index {
  width: 1.6rem;
  height: 1.6rem;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  background: var(--xana-accent-soft);
  color: var(--xana-accent);
  font-size: 0.72rem;
  font-weight: 900;
}

.xana-path-hop-arrow {
  color: var(--xana-accent);
  font-size: 0.9rem;
  font-weight: 900;
}

.xana-path-hop-rel {
  color: #ffd166;
  font-size: 0.78rem;
  font-weight: 800;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  justify-self: center;
}

.xana-path-node-chip {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  max-width: 100%;
  padding: 0.22rem 0.55rem;
  border-radius: 999px;
  background: var(--xana-accent-soft);
  color: var(--xana-text);
  font-size: 0.78rem;
  font-weight: 800;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.xana-path-node-dir {
  color: var(--xana-text-muted);
  font-size: 0.68rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.xana-path-hop-from,
.xana-path-hop-to {
  min-width: 0;
}

@media (max-width: 900px) {
  .xana-path-page {
    padding: 5.5rem 1rem 2.5rem;
  }

  .xana-path-grid {
    grid-template-columns: 1fr;
  }

  .xana-path-hop {
    grid-template-columns: auto minmax(0, 1fr);
    row-gap: 0.35rem;
  }

  .xana-path-hop-rel,
  .xana-path-hop-arrow {
    justify-self: start;
  }

  .xana-path-card-endpoints {
    justify-content: flex-start;
  }
}

@media (max-width: 700px) {
  .xana-path-page {
    padding: 5rem 1rem 2rem;
  }
}

/* ── Node violations panel section ──────────────────────────────────────── */

.xana-violations-section {
  margin-top: 2rem;
  padding-top: 1.25rem;
  border-top: 1px solid rgba(255, 107, 107, 0.3);
}

.xana-violations-section h2 {
  font-size: 0.82rem;
  font-weight: 850;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: #ff6b6b;
  margin: 0 0 0.6rem;
}

.xana-violations-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: 0.3rem;
}

.xana-violation {
  background: rgba(255, 107, 107, 0.1);
  border: 1px solid rgba(255, 107, 107, 0.3);
  border-radius: 0.5rem;
  padding: 0.4rem 0.65rem;
  font-size: 0.8rem;
  color: #ffd6d6;
}

/* ── Filter legacy type label ────────────────────────────────────────────── */

.xana-filter-legacy {
  opacity: 0.6;
}

.xana-filter-legacy:hover {
  opacity: 1;
}
